// Validate and format DLQ input
const rawInput = $input.first().json;
const input = rawInput.body || rawInput;

// Required fields
const required = ['failure_reason', 'original_payload'];
for (const field of required) {
  if (!input[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Prepare flat object for Postgres
return [{
  json: {
    payload: {
      booking_id: parseInt(input.booking_id) || 0,
      idempotency_key: (input.idempotency_key || '').toString(),
      provider_id: parseInt(input.provider_id) || 1,
      service_id: parseInt(input.service_id) || 1,
      start_time: input.start_time || new Date().toISOString(),
      customer_id: (input.customer_id || input.chat_id || '').toString(),
      chat_id: (input.chat_id || 0).toString(),
      failure_reason: (input.failure_reason || 'unknown').toString(),
      last_error_message: (input.error_message || input.failure_reason || 'Unknown error').toString(),
      last_error_stack: (input.error_stack || '').toString(),
      original_payload: input.original_payload,
      context_data: input.context_data || {
        workflow_id: input.workflow_id || 'UNKNOWN',
        execution_id: input.execution_id || 'MANUAL',
        failed_at: new Date().toISOString()
      }
    }
  }
}];

// Return DLQ addition result
const dbResult = $('Add to DLQ DB').first().json;
const payload = $('Validate DLQ Input').first().json.payload;

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      dlq_id: dbResult.booking_dlq_add,
      added_to_dlq: true,
      failure_count: 1,
      next_retry_at: new Date(Date.now() + 2 * 60000).toISOString(),
      message: `Booking added to Dead Letter Queue. ID: ${dbResult.booking_dlq_add}`,
      idempotency_key: payload.idempotency_key
    },
    _meta: {
      source: 'DLQ_MANAGER',
      timestamp: new Date().toISOString(),
      version: '1.1.0'
    }
  }
}];

// Return DLQ status summary
const status = $('Get DLQ Status').all();

const summary = status.reduce((acc, item) => {
  acc[item.json.status] = {
    count: item.json.count,
    oldest: item.json.oldest_failure,
    avg_failures: parseFloat(item.json.avg_failure_count || 0).toFixed(2)
  };
  return acc;
}, {});

return [{
  json: {
    success: true,
    error_code: null,
    error_message: null,
    data: {
      summary: summary,
      total_items: status.reduce((sum, item) => sum + (item.json.count || 0), 0),
      generated_at: new Date().toISOString()
    },
    _meta: {
      source: 'DLQ_MANAGER',
      timestamp: new Date().toISOString(),
      version: '1.0.0'
    }
  }
}];
